33→export function pointInPolygon(point, polygon) {
34→  let inside = false;
35→  const n = polygon.length;
36→  for (let i = 0, j = n - 1; i < n; j = i++) {
37→    const xi = polygon[i].x, yi = polygon[i].y;
38→    const xj = polygon[j].x, yj = polygon[j].y;
39→    if (
40→      yi > point.y !== yj > point.y &&
41→      point.x < ((xj - xi) * (point.y - yi)) / (yj - yi) + xi
42→    ) {
43→      inside = !inside;
44→    }
45→  }
46→  return inside;
47→}
